package com.mms.job.common.constant;import org.springframework.util.StringUtils;/** * 实现功能【经网关调用各业务服务内部定时任务接口的 URL 拼装】 * <p> * 路径须与网关路由 {@code /api/{service}/**}（StripPrefix=2）及 {@code JobExecuteController} 一致。 * 主机名 {@code gateway} 为 Nacos 服务名，配合 {@code @LoadBalanced RestTemplate} 解析。 * </p> * * @author li.hongyu * @date 2026-05-22 14:00:00 */public final class JobInternalGatewayUrls {    /**     * 网关在 Nacos 中的服务名（无 ip:port，由负载均衡解析）     */    private static final String SCHEME_HOST = "http://gateway";    private static final String API_PREFIX = "/api";    private static final String INTERNAL_JOB_PREFIX = "/internal/job";    private static final String EXECUTE_SUFFIX = "/execute";    private static final String VALIDATE_SUFFIX = "/validate";    /**     * 执行任务：{@code POST /api/{serviceName}/internal/job/execute}     */    public static String executeUrl(String serviceName) {        return build(serviceName, EXECUTE_SUFFIX);    }    /**     * 校验任务参数：{@code POST /api/{serviceName}/internal/job/validate}     */    public static String validateUrl(String serviceName) {        return build(serviceName, VALIDATE_SUFFIX);    }    private static String build(String serviceName, String actionSuffix) {        if (!StringUtils.hasText(serviceName)) {            throw new IllegalArgumentException("serviceName 不能为空");        }        return SCHEME_HOST + API_PREFIX + "/" + serviceName.trim() + INTERNAL_JOB_PREFIX + actionSuffix;    }    private JobInternalGatewayUrls() {        throw new UnsupportedOperationException("常量类不允许实例化");    }}